// Ступень 5–7 лет · «Формы оживают» — неделя 1 (дни 1–5, 50 уроков).
// Калибровка: схематичная стадия — ребёнок собирает мир из кругов, овалов и
// треугольников, рисует человечков, дом и линию земли. Толстая уверенная линия
// (контур 4.5–5), никакого штриха/эллипсов-объёма. Каркас: docs/RISOVANIE-5-7-KARKAS.md.

const VIEW = '0 0 300 210';

function step(hint, layer) {
  return { hint, layer };
}

function paper(fill = '#fffdf7') {
  return `<path d="M0 0 H300 V210 H0 Z" fill="${fill}"/>`;
}

function lesson(day, index, data) {
  const level = index < 3 ? 1 : index < 7 ? 2 : 3;
  return {
    slug: `art57-d${String(day).padStart(2, '0')}-${String(index + 1).padStart(2, '0')}-${data.slug}`,
    ageBand: '5-7',
    level,
    title: data.title,
    theme: data.theme,
    chapter: data.chapter,
    skill: data.skill,
    kind: data.kind ?? (level === 3 ? 'combo' : level === 2 ? 'fantasy' : 'draw'),
    order: day * 100 + index + 1,
    free: true,
    cover: data.cover,
    viewBox: VIEW,
    coloredViewBox: VIEW,
    canvas: 'landscape',
    palette: data.palette,
    intro: data.intro,
    steps: data.steps,
    coloredPreview: data.preview,
    storyStageLabel: level === 1 ? 'разминка' : level === 2 ? 'приём дня' : 'я художник',
    storyPrompt: data.storyPrompt,
    storyMissions: data.storyMissions,
    colorHint: data.colorHint,
    finishIdea: data.finishIdea,
    parentNote: data.parentNote,
  };
}

